package v1alpha1

import (
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/runtime/schema"
)

const (
	GroupName = "runtime.agentcube.volcano.sh"
	Version   = "v1alpha1"
)

var (
	SchemeBuilder = runtime.NewSchemeBuilder(AddKnownTypes)
	Scheme        = runtime.NewSchemeBuilder(AddToScheme)

	AgentRuntimeGVR = schema.GroupVersionResource{
		Group:    GroupName,
		Version:  Version,
		Resource: "agentruntimes",
	}

	CodeInterpreterGVR = schema.GroupVersionResource{
		Group:    GroupName,
		Version:  Version,
		Resource: "codeinterpreters",
	}
)

func AddKnownTypes(scheme *runtime.Scheme) error {
	scheme.AddKnownTypes(GroupVersion,
		&AgentRuntime{},
		&AgentRuntimeList{},
		&CodeInterpreter{},
		&CodeInterpreterList{},
	)
	return nil
}

func AddToScheme(scheme *runtime.Scheme) error {
	return SchemeBuilder.AddToScheme(scheme)
}

