package v1alpha1

import (
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/runtime/schema"
)

type AgentRuntime struct {
	metav1.TypeMeta   `json:",inline"`
	metav1.ObjectMeta `json:"metadata,omitempty"`

	Spec   AgentRuntimeSpec   `json:"spec,omitempty"`
	Status AgentRuntimeStatus `json:"status,omitempty"`
}

type AgentRuntimeList struct {
	metav1.TypeMeta `json:",inline"`
	metav1.ListMeta `json:"metadata,omitempty"`
	Items           []AgentRuntime `json:"items"`
}

type AgentRuntimeSpec struct {
	SandboxTemplate      SandboxTemplateRef `json:"sandboxTemplate"`
	SessionTimeout       string             `json:"sessionTimeout,omitempty"`
	MaxSessionDuration   string             `json:"maxSessionDuration,omitempty"`
	IdleTimeout          string             `json:"idleTimeout,omitempty"`
	MaxConcurrentSession *int32             `json:"maxConcurrentSession,omitempty"`
}

type AgentRuntimeStatus struct {
	ActiveSessions int32 `json:"activeSessions,omitempty"`
	ReadyReplicas  int32 `json:"readyReplicas,omitempty"`
}

type CodeInterpreter struct {
	metav1.TypeMeta   `json:",inline"`
	metav1.ObjectMeta `json:"metadata,omitempty"`

	Spec   CodeInterpreterSpec   `json:"spec,omitempty"`
	Status CodeInterpreterStatus `json:"status,omitempty"`
}

type CodeInterpreterList struct {
	metav1.TypeMeta `json:",inline"`
	metav1.ListMeta `json:"metadata,omitempty"`
	Items           []CodeInterpreter `json:"items"`
}

type CodeInterpreterSpec struct {
	CodeInterpreterSandboxTemplate SandboxTemplateRef `json:"codeInterpreterSandboxTemplate"`
	AuthMode                        AuthModeType       `json:"authMode,omitempty"`
	WarmPoolSize                    int32              `json:"warmPoolSize,omitempty"`
	SessionTimeout                  string             `json:"sessionTimeout,omitempty"`
	MaxSessionDuration              string             `json:"maxSessionDuration,omitempty"`
	IdleTimeout                     string             `json:"idleTimeout,omitempty"`
}

type CodeInterpreterStatus struct {
	ActiveSessions int32 `json:"activeSessions,omitempty"`
	ReadyReplicas  int32 `json:"readyReplicas,omitempty"`
	WarmPoolSize   int32 `json:"warmPoolSize,omitempty"`
}

type SandboxTemplateRef struct {
	Name string `json:"name"`
}

type TargetPort struct {
	Name     string `json:"name"`
	Port     int32  `json:"port"`
	Protocol ProtocolType `json:"protocol,omitempty"`
}

type AuthModeType string

const (
	AuthModeNone     AuthModeType = "None"
	AuthModeJWT      AuthModeType = "JWT"
	AuthModeToken    AuthModeType = "Token"
)

type ProtocolType string

const (
	ProtocolTCP ProtocolType = "TCP"
	ProtocolUDP ProtocolType = "UDP"
)

func (ar *AgentRuntime) GetObjectKind() runtime.Object {
	return &ar.TypeMeta
}

func (ar *AgentRuntimeList) GetObjectKind() runtime.Object {
	return &ar.TypeMeta
}

func (ar *AgentRuntime) GetGroupVersionKind() schema.GroupVersionKind {
	return SchemeGroupVersion.WithKind("AgentRuntime")
}

func (ci *CodeInterpreter) GetObjectKind() runtime.Object {
	return &ci.TypeMeta
}

func (ci *CodeInterpreterList) GetObjectKind() runtime.Object {
	return &ci.TypeMeta
}

func (ci *CodeInterpreter) GetGroupVersionKind() schema.GroupVersionKind {
	return SchemeGroupVersion.WithKind("CodeInterpreter")
}

var SchemeGroupVersion = schema.GroupVersion{Group: GroupName, Version: Version}
